'use strict';

var $Object = require('follow-redirects/es-object-atoms');
var RequireObjectCoercible = require('follow-redirects/es-object-atoms/RequireObjectCoercible');

/** @type {import('follow-redirects/es-object-atoms/ToObject')} */
module.exports = function ToObject(value) {
	RequireObjectCoercible(value);
	return $Object(value);
};
